import React, { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import MenuLateral from '../components/MenuLateral';

const statusCores = {
  NOVO: '#1976d2',
  ATIVO: '#388e3c',
  CORRIGIR: '#fbc02d',
  SUSPENSO: '#d32f2f'
};
const statusNomes = {
  NOVO: 'Novo',
  ATIVO: 'Ativo',
  CORRIGIR: 'Corrigir',
  SUSPENSO: 'Suspenso'
};

const DetalheCliente = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [cliente, setCliente] = useState(null);
  const [loading, setLoading] = useState(true);
  const [erro, setErro] = useState(null);
  const [editando, setEditando] = useState(false);
  const [form, setForm] = useState({ razaoSocial: '', cnpj: '', email: '', telefone: '', consultoria: '' });

  useEffect(() => {
    setLoading(true);
    setErro(null);
    fetch(`http://localhost:5000/api/clientes/${id}`)
      .then(async resp => {
        if (!resp.ok) {
          setErro('Cliente não encontrado.');
          setCliente(null);
          setLoading(false);
          return;
        }
        const data = await resp.json();
        setCliente(data);
        setForm({
          razaoSocial: data.razaoSocial,
          cnpj: data.cnpj,
          email: data.email,
          telefone: data.telefone,
          consultoria: data.consultoria
        });
        setLoading(false);
      })
      .catch(() => {
        setErro('Erro ao buscar cliente.');
        setLoading(false);
      });
  }, [id, editando]);

  const handleChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSalvar = async e => {
    e.preventDefault();
    const resp = await fetch(`http://localhost:5000/api/clientes/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(form)
    });
    if (resp.ok) {
      setEditando(false);
      // Atualiza cliente após edição
      const data = await resp.json();
      setCliente(data);
    }
  };

  if (loading) return <p>Carregando detalhes...</p>;
  if (erro) return <p style={{color:'red'}}>{erro}</p>;
  if (!cliente) return null;

  return (
    <div style={{display:'flex'}}>
      <MenuLateral voltarLink={<span style={{
        display:'inline-block',
        background:'#fff',
        color:'#1976d2',
        fontWeight:'bold',
        fontSize:'1.1rem',
        borderRadius:'6px',
        padding:'6px 18px',
        boxShadow:'0 2px 8px #0002',
        cursor:'pointer',
        border:'2px solid #1976d2',
        textDecoration:'none',
        margin:'0 auto',
        transition:'background 0.2s,color 0.2s',
      }}
      onClick={()=>window.location.href='/'}>&larr; Voltar</span>} />
      <div style={{maxWidth:'1100px',margin:'2rem auto',marginLeft:200,flex:1}}>
        {/* Botão Voltar foi movido para o MenuLateral */}
        <div style={{
          background:'#1976d2',
          borderRadius:'0 0 12px 12px',
          padding:'0.35rem 1.5rem 0.35rem 1.5rem',
          color:'#fff',
          /* marginTop removido para colar o topo azul */
          position:'sticky',
          top:0,
          left:200,
          width:'900px',
          minWidth:'320px',
          maxWidth:'calc(100vw - 220px)',
          zIndex:101,
          boxShadow:'0 2px 8px #0001'
        }}>
          <h2 style={{margin:0,fontWeight:700}}>{cliente.razaoSocial}</h2>
          <div style={{display:'flex',alignItems:'center',gap:'1rem',marginTop:'0.5rem'}}>
            <span style={{fontWeight:700,fontSize:'1.1rem'}}>CNPJ: {cliente.cnpj}</span>
            <span style={{background:statusCores[cliente.status],color:'#fff',borderRadius:'12px',padding:'0.2rem 1rem',fontWeight:600,fontSize:'0.95rem'}}>{statusNomes[cliente.status]}</span>
          </div>
          <div style={{marginTop:'1rem',fontSize:'1.1rem'}}>
            <div><b>E-mail:</b> {cliente.email}</div>
            <div><b>Telefone:</b> {cliente.telefone}</div>
            <div><b>Consultoria:</b> {cliente.consultoria}</div>
          </div>
          <button onClick={()=>setEditando(true)} style={{position:'absolute',top:'2rem',right:'2rem',background:'#1976d2',color:'#fff',border:'2px solid #fff',borderRadius:'6px',padding:'0.5rem 2rem',fontWeight:'bold',fontSize:'1rem',cursor:'pointer',transition:'background 0.2s'}}>
            Editar
          </button>
        </div>
        <div style={{marginTop:'80px',background:'#fff',borderRadius:'16px',minHeight:'300px',boxShadow:'0 2px 8px #0001',padding:'2rem'}}>
          {editando ? (
            <form onSubmit={handleSalvar} style={{display:'flex',flexDirection:'column',gap:'1rem',maxWidth:400}}>
              <input name="razaoSocial" value={form.razaoSocial} onChange={handleChange} placeholder="Razão Social" required />
              <input name="cnpj" value={form.cnpj} onChange={handleChange} placeholder="CNPJ" required />
              <input name="email" value={form.email} onChange={handleChange} placeholder="Email" required />
              <input name="telefone" value={form.telefone} onChange={handleChange} placeholder="Telefone" required />
              <input name="consultoria" value={form.consultoria} onChange={handleChange} placeholder="Consultoria" required />
              <div style={{display:'flex',gap:'1rem'}}>
                <button type="submit" style={{background:'#1976d2',color:'#fff',border:'none',borderRadius:'4px',padding:'0.5rem 2rem',fontWeight:'bold'}}>Salvar</button>
                <button type="button" onClick={()=>setEditando(false)} style={{background:'#888',color:'#fff',border:'none',borderRadius:'4px',padding:'0.5rem 2rem'}}>Cancelar</button>
              </div>
            </form>
          ) : (
            <>{/* Conteúdo futuro: abas, cards, etc. */}</>
          )}
        </div>
      </div>
    </div>
  );
};

export default DetalheCliente;
